    def _load(self) -> None:
        self._module = importlib.import_module(self.module_name)
        factory = getattr(self._module, self.factory_name, None)
        if not callable(factory):
            raise HandlerError(f"Handler factory '{self.factory_name}' not found in module '{self.module_name}'")
        self._factory = factory

    def get_handler(self, event: Dict[str, Any]) -> Callable[[Dict[str, Any]], Any]:
        if self._factory is None:
            self._load()
        assert self._factory is not None
        handler = self._factory(event)
        if not callable(handler):
            raise HandlerError("Factory did not return a callable handler")
        return handler


